/// <reference lib="webworker" />
import { registerApplicationBehavior, ScriptBuilder } from '@universal-robots/contribution-api';
import { DISPLAY_REMOTE_APPLICATION_NODE_TYPE } from './display-remote-application.node';
const createApplicationNode = () => ({
  type: DISPLAY_REMOTE_APPLICATION_NODE_TYPE,
  version: '1.0.0',
  remoteUrl: ''
});
const generatePreambleScriptCode = _node => {
  return new ScriptBuilder();
};
const mergeApplicationNode = (loadedNode, defaultNode) => {
  const loaded = loadedNode;
  return {
    ...defaultNode,
    ...loaded,
    remoteUrl: loaded.remoteUrl ?? ''
  };
};
const upgradeApplicationNode = (loadedNode, defaultNode) => mergeApplicationNode(loadedNode, defaultNode);
const downgradeApplicationNode = (loadedNode, defaultNode) => mergeApplicationNode(loadedNode, defaultNode);
const behaviors = {
  factory: createApplicationNode,
  generatePreamble: generatePreambleScriptCode,
  upgradeNode: upgradeApplicationNode,
  downgradeNode: downgradeApplicationNode
};
registerApplicationBehavior(behaviors);
